import{_ as t,o as a,c as o,a2 as n}from"./chunks/framework.CKCxdkvf.js";const m=JSON.parse('{"title":"ADR-018 — Mobile-first design, bottom sheet panel pattern","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-018.md","filePath":"adr/ADR-018.md"}'),s={name:"adr/ADR-018.md"};function i(r,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="adr-018-—-mobile-first-design-bottom-sheet-panel-pattern" tabindex="-1">ADR-018 — Mobile-first design, bottom sheet panel pattern <a class="header-anchor" href="#adr-018-—-mobile-first-design-bottom-sheet-panel-pattern" aria-label="Permalink to &quot;ADR-018 — Mobile-first design, bottom sheet panel pattern&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 TA anchor · §stack · §components</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>At the scale of millions of users, roughly half will be on mobile devices. The current prototypes are desktop-only. Mobile must be designed in from the start, not retrofitted.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Mobile-first design throughout. The base CSS targets small screens; larger screens progressively enhance. The detail panel pattern is a <strong>bottom sheet</strong> (slides up from the bottom edge) on small screens and a right-side drawer on large screens. Minimum touch target size: 44×44px (iOS HIG / Material Design). Three.js screens support single-finger orbit and two-finger pinch-zoom.</p><p>Breakpoints:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mobile:  &lt; 768px   (base — design here first)</span></span>
<span class="line"><span>tablet:  768–1024px</span></span>
<span class="line"><span>desktop: &gt; 1024px</span></span></code></pre></div><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>A bottom sheet is the correct mobile pattern for contextual detail content — it is native to both iOS and Android, leaves the canvas visible behind it, and dismisses with a swipe-down gesture. The right-side drawer is correct on desktop where 314px of panel width is available without obscuring the canvas. SvelteKit components render the appropriate pattern via a CSS media query and a shared panel component that adapts its position.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Full-screen modal on mobile</strong> — hides the canvas entirely; worse for context; rejected.</li><li><strong>Desktop-only for v1</strong> — wrong assumption at production scale; rejected.</li><li><strong>Responsive right panel</strong> — scales the right panel narrower on mobile; 200px panels are illegible; rejected.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: genuinely usable on mobile from day one; bottom sheet is a native-feeling pattern; no UX debt to pay later. Negative: every component must be designed at mobile size first; the porkchop plot (PRD-002) requires a separate mobile interaction design; Three.js touch handling must be explicit.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>CSS custom properties for breakpoints. Svelte components accept a <code>variant: &#39;sheet&#39; | &#39;drawer&#39;</code> prop determined by a <code>matchMedia</code> store. Three.js touch: <code>touchstart</code>/<code>touchmove</code> listeners for orbit; <code>gesturechange</code> or two-touch distance delta for zoom. Panel component is shared; layout variant is determined at runtime.</p>`,16)])])}const u=t(s,[["render",i]]);export{m as __pageData,u as default};
